let cachedBootcode = '';

function getPostmanSandboxBootcode() {
  if (!cachedBootcode) {
    cachedBootcode = zlib.gunzipSync(Buffer.from(POSTMAN_SANDBOX_BOOTCODE_GZIP_BASE64, 'base64')).toString('utf8');
    const digest = crypto.createHash('sha256').update(cachedBootcode).digest('hex');
    if (digest !== POSTMAN_SANDBOX_BOOTCODE_SHA256) {
      throw new Error('Vendored Postman sandbox bootcode integrity check failed.');
    }
  }
  return cachedBootcode;
}

module.exports = {
  POSTMAN_SANDBOX_BOOTCODE_SHA256,
  POSTMAN_SANDBOX_BOOTCODE_SOURCE_SHA256,
  POSTMAN_SANDBOX_BOOTCODE_SOURCE_VERSION,
  getPostmanSandboxBootcode
};
